    }

    observer = new MutationObserver(function () {
      updatePublishDate();
    });

    observer.observe(target, {
      childList: true,
      subtree: true,
      characterData: true
    });

    window.setTimeout(function () {
      observer.disconnect();
    }, 30000);
  }

  ready(function () {
    updatePublishDate();
    startObserver();
    retryUpdate();
  });
